class Solution {
public:
    string largestPalindrome(int n, int k) {
        if (n == 1) return to_string(k * (9 / k));
        string half(n / 2, '9');
        string full;
        if (n & 1) {
            for (int d = 9; d >= 0; --d) {
                full = half + char('0' + d) + string(half.rbegin(), half.rend());
                if (stoll(full) % k == 0) return full;
            }
        } else {
            full = half + string(half.rbegin(), half.rend());
            long long val = stoll(full);
            long long rem = val % k;
            if (rem == 0) return full;
            long long delta = rem > val ? k - rem : -rem;
            val += delta;
            if (val < 0) val += k;
            full = to_string(val);
            if (full.size() != n) {
                for (int i = 0; i < n / 2; ++i) half[i] = '8';
                full = half + string(half.rbegin(), half.rend());
            }
        }
        return full;
    }
};
